// Find our date picker inputs on the page
const startInput = document.getElementById('startDate');
const endInput = document.getElementById('endDate');

// Call the setupDateInputs function from dateRange.js
// This sets up the date pickers to:
// - Default to a range of 9 days (from 9 days ago to today)
// - Restrict dates to NASA's image archive (starting from 1995)

let API_KEY = "tgG3PTPmlj8EjMWk1gfQeYFecLShU8mxlbtTTyuR";
setupDateInputs(startInput, endInput);

const startDate = document.getElementById("startDate");
const endDate = document.getElementById("endDate");
const imageButton = document.getElementById("imageButton");
const caption = document.getElementById("caption");
const thumbs = true;
let container = document.getElementById("gallery")

imageButton.addEventListener("click", function() {
    /*
  *
  * first display loading message like Loading space Photos...
  *
  * https request:    GET https://api.nasa.gov/planetary/apod?api_key=tgG3PTPmlj8EjMWk1gfQeYFecLShU8mxlbtTTyuR
  *
  *
  * how do I want this function to work? when clicked call the api first?
  * then output the data within the range? startDate to endDate
  *
  *
  * */

    console.log("startDate is " + startDate.value + " to " + endDate.value);

    caption.innerHTML = "Loading Space Photos..."
    getImages()









});

function getImages() {

    fetch(`https://api.nasa.gov/planetary/apod?api_key=${API_KEY}&start_date=${startDate.value}&end_date=${endDate.value}&thumbs=${thumbs}`)

        .then(response => response.json())
        .then(data => {
            console.log(data)




                container.innerHTML = "";
                data.forEach((element) => {
                    let media;

                    if (element.media_type === "video") {
                        media = `<video src="${element.url}" controls width="300" height="300"></video>`;
                    } else {
                        media = `<img src="${element.url}" width="300" height="300" />`;
                    }

                    const mediaHTML = `
                        <div class="photoCard col  text-center ">
                            ${media}
                            <h5>${element.title}</h5>

                        </div>
                    `;

                    container.innerHTML += mediaHTML;
                });



        })
        .catch(error => {

        console.log(error);
        // const errorMsg = document.createTextNode(`Error:${data.error} `);
        let errorMsg;

        if(error.message === "Failed to fetch"){
             errorMsg = document.createTextNode("Error: You are Offline");
        }else{
             errorMsg = document.createTextNode(`Error: ${error.message}`);
        }

        let errorDiv = document.createElement("div");
        errorDiv.appendChild(errorMsg);
        errorDiv.className = "error-message";

        let container = document.getElementById("gallery")

        container.innerHTML = "";
        container.appendChild(errorDiv);

    });

}

// Find our date picker inputs on the page
const startInput = document.getElementById('startDate');
const endInput = document.getElementById('endDate');

// Call the setupDateInputs function from dateRange.js
// This sets up the date pickers to:
// - Default to a range of 9 days (from 9 days ago to today)
// - Restrict dates to NASA's image archive (starting from 1995)

let API_KEY = "tgG3PTPmlj8EjMWk1gfQeYFecLShU8mxlbtTTyuR";
setupDateInputs(startInput, endInput);

const startDate = document.getElementById("startDate");
const endDate = document.getElementById("endDate");
const imageButton = document.getElementById("imageButton");
const caption = document.getElementById("caption");
const thumbs = true;
let container = document.getElementById("gallery")

imageButton.addEventListener("click", function() {
    /*
  *
  * first display loading message like Loading space Photos...
  *
  * https request:    GET https://api.nasa.gov/planetary/apod?api_key=tgG3PTPmlj8EjMWk1gfQeYFecLShU8mxlbtTTyuR
  *
  *
  * how do I want this function to work? when clicked call the api first?
  * then output the data within the range? startDate to endDate
  *
  *
  * */

    console.log("startDate is " + startDate.value + " to " + endDate.value);

    caption.innerHTML = "Loading Space Photos..."
    getImages()









});

function getImages() {

    fetch(`https://api.nasa.gov/planetary/apod?api_key=${API_KEY}&start_date=${startDate.value}&end_date=${endDate.value}&thumbs=${thumbs}`)

        .then(response => response.json())
        .then(data => {
            console.log(data)




                container.innerHTML = "";
                data.forEach((element) => {
                    let media;

                    if (element.media_type === "video") {
                        media = `<video src="${element.url}" controls class="card-img-top"></video>`;
                    } else {
                        media = `<img src="${element.url}" class="card-img-top" />`;
                    }

                    const mediaHTML = `
                        <div class="col-md-4 mb-4">
                            <div class="card">
                                ${media}
                                <div class="card-body">
                                    <h5 class="card-title">${element.title}</h5>
                                </div>
                            </div>
                        </div>
                    `;

                    container.innerHTML += mediaHTML;
                });



        })
        .catch(error => {

        console.log(error);
        // const errorMsg = document.createTextNode(`Error:${data.error} `);
        let errorMsg;

        if(error.message === "Failed to fetch"){
             errorMsg = document.createTextNode("Error: You are Offline");
        }else{
             errorMsg = document.createTextNode(`Error: ${error.message}`);
        }

        let errorDiv = document.createElement("div");
        errorDiv.appendChild(errorMsg);
        errorDiv.className = "error-message";

        let container = document.getElementById("gallery")

        container.innerHTML = "";
        container.appendChild(errorDiv);

    });

}
